import json
import re

raw_data_string = locals()['var_function-call-12499936828729546505']['results'][0]

# Extract the JSON array string from the raw data string
json_array_str_match = re.search(r'\[.*?\]', raw_data_string, re.DOTALL)

if json_array_str_match:
    json_array_str = json_array_str_match.group(0)
    data = json.loads(json_array_str)
    symbol_company = {item['Symbol']: item['Company Description'] for item in data}
else:
    symbol_company = {}

print("__RESULT__:")
print(json.dumps(symbol_company))

